#!/usr/bin/env python
import os
import sys
import tarfile
import zipfile
import subprocess
import shutil
from datetime import datetime

def validate_format(format_type):
    """Validate and return the compression format."""
    allowed_formats = ['tar.gz', 'tar.bz2', 'zip', '7z']
    if format_type not in allowed_formats:
        raise ValueError(f"Invalid format. Allowed formats: {', '.join(allowed_formats)}")
    return format_type

def validate_directory(directory_path):
    """Validate that the directory exists and is a directory."""
    if not os.path.exists(directory_path):
        raise ValueError(f"Directory does not exist: {directory_path}")
    if not os.path.isdir(directory_path):
        raise ValueError(f"Path is not a directory: {directory_path}")
    abs_path = os.path.abspath(directory_path)
    return abs_path

def get_archive_name(directory_path, format_type):
    """Generate archive filename with timestamp."""
    base_name = os.path.basename(directory_path.rstrip(os.sep))
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    
    if format_type == 'tar.gz':
        extension = '.tar.gz'
    elif format_type == 'tar.bz2':
        extension = '.tar.bz2'
    elif format_type == 'zip':
        extension = '.zip'
    elif format_type == '7z':
        extension = '.7z'
    
    return f"{base_name}_backup_{timestamp}{extension}"

def create_tar_archive(directory_path, output_file, compression_mode):
    """Create tar archive with specified compression."""
    with tarfile.open(output_file, compression_mode) as tar:
        tar.add(directory_path, arcname=os.path.basename(directory_path))
    return output_file

def create_zip_archive(directory_path, output_file):
    """Create zip archive."""
    with zipfile.ZipFile(output_file, 'w', zipfile.ZIP_DEFLATED) as zipf:
        for root, dirs, files in os.walk(directory_path):
            for file in files:
                file_path = os.path.join(root, file)
                arcname = os.path.relpath(file_path, os.path.dirname(directory_path))
                zipf.write(file_path, arcname)
    return output_file

def create_7z_archive(directory_path, output_file):
    """Create 7z archive using 7z command."""
    seven_zip_path = shutil.which('7z')
    if not seven_zip_path:
        seven_zip_path = shutil.which('7za')
    
    if not seven_zip_path:
        raise RuntimeError("7z executable not found. Please install p7zip.")
    
    abs_output = os.path.abspath(output_file)
    abs_directory = os.path.abspath(directory_path)
    
    try:
        subprocess.check_call(
            [seven_zip_path, 'a', '-t7z', abs_output, abs_directory],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE
        )
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"Failed to create 7z archive: {e}")
    
    return abs_output

def create_backup(directory_path, format_type):
    """Create backup archive of the specified directory."""
    validated_format = validate_format(format_type)
    validated_directory = validate_directory(directory_path)
    
    archive_name = get_archive_name(validated_directory, validated_format)
    output_path = os.path.join(os.getcwd(), archive_name)
    
    print(f"Creating backup of: {validated_directory}")
    print(f"Format: {validated_format}")
    print(f"Output: {output_path}")
    
    try:
        if validated_format == 'tar.gz':
            result = create_tar_archive(validated_directory, output_path, 'w:gz')
        elif validated_format == 'tar.bz2':
            result = create_tar_archive(validated_directory, output_path, 'w:bz2')
        elif validated_format == 'zip':
            result = create_zip_archive(validated_directory, output_path)
        elif validated_format == '7z':
            result = create_7z_archive(validated_directory, output_path)
        
        file_size = os.path.getsize(result)
        print(f"Backup created successfully: {result}")
        print(f"Archive size: {file_size / (1024*1024):.2f} MB")
        return result
        
    except Exception as e:
        print(f"Error creating backup: {e}")
        if os.path.exists(output_path):
            os.remove(output_path)
        raise

def main():
    if len(sys.argv) != 3:
        print("Usage: python backup_script.py <directory_path> <format>")
        print("Supported formats: tar.gz, tar.bz2, zip, 7z")
        sys.exit(1)
    
    directory_path = sys.argv[1]
    format_type = sys.argv[2]
    
    try:
        create_backup(directory_path, format_type)
    except Exception as e:
        print(f"Backup failed: {e}")
        sys.exit(1)

if __name__ == '__main__':
    main()